def verify(answer):
    from sympy import symbols, Eq, solve
    a, b, c = symbols('a b c')
    eq = Eq(2*a**3 + 7*a**2 - 8*a + 5, 0)
    solutions = solve(eq, a)
    products = []
    for p in itertools.permutations(solutions, 3):
        if len(set(p)) == 3:  # distinct numbers
            products.append(p[0]*p[1]*p[2])
    try:
        return int(str(answer).strip()) in products
    except Exception:
        return False

def verify(answer):
    def is_prime(n):
        if n < 2:
            return False
