from itertools import permutations

def verify(answer):
    digits = [3, 4, 6, 7, 8, 9]
    max_multiple = 0
    for p in permutations(digits):
        num = int(''.join(map(str, p)))
        if num % 4 == 0 and num > max_multiple:
            max_multiple = num
    try:
        return int(str(answer).strip()) == max_multiple
    except Exception:
        return False

